<?php

declare(strict_types=1);

function sf_pch_text($value,int $max=12000):string{$value=trim((string)$value);return function_exists('mb_substr')?mb_substr($value,0,$max):substr($value,0,$max);}
function sf_pch_uuid():string{$b=random_bytes(16);$b[6]=chr((ord($b[6])&0x0f)|0x40);$b[8]=chr((ord($b[8])&0x3f)|0x80);$h=bin2hex($b);return substr($h,0,8).'-'.substr($h,8,4).'-'.substr($h,12,4).'-'.substr($h,16,4).'-'.substr($h,20);}
function sf_pch_ready():bool{return sf_admin_db() instanceof PDO&&sf_admin_table_exists('production_cutover_runs')&&sf_admin_table_exists('production_cutover_checks')&&sf_admin_table_exists('production_cutover_evidence')&&sf_admin_table_exists('production_cutover_events')&&sf_admin_table_exists('production_cutover_decisions')&&sf_admin_table_exists('production_hypercare_checkpoints')&&sf_admin_table_exists('production_hypercare_metrics')&&sf_admin_table_exists('production_verification_certificates');}
function sf_pch_locked(array $run):bool{return in_array((string)($run['run_status']??''),['completed','rolled_back','aborted','failed'],true);}
function sf_pch_run(int $id):?array{return sf_pch_ready()&&$id>0?sf_admin_fetch_one('SELECT * FROM production_cutover_runs WHERE id=? LIMIT 1',[$id]):null;}
function sf_pch_runs(int $limit=60):array{return sf_pch_ready()?sf_admin_fetch_all('SELECT * FROM production_cutover_runs ORDER BY created_at DESC,id DESC LIMIT '.max(1,min(200,$limit))):[];}
function sf_pch_checks(int $runId):array{return sf_pch_ready()&&$runId>0?sf_admin_fetch_all("SELECT * FROM production_cutover_checks WHERE run_id=? ORDER BY FIELD(severity,'critical','high','medium','low','info'),section_key,id",[$runId]):[];}
function sf_pch_events(int $runId,int $limit=200):array{return sf_pch_ready()&&$runId>0?sf_admin_fetch_all('SELECT * FROM production_cutover_events WHERE run_id=? ORDER BY created_at DESC,id DESC LIMIT '.max(1,min(500,$limit)),[$runId]):[];}
function sf_pch_decisions(int $runId):array{return sf_pch_ready()&&$runId>0?sf_admin_fetch_all('SELECT * FROM production_cutover_decisions WHERE run_id=? ORDER BY decided_at DESC,id DESC',[$runId]):[];}
function sf_pch_checkpoints(int $runId):array{return sf_pch_ready()&&$runId>0?sf_admin_fetch_all('SELECT * FROM production_hypercare_checkpoints WHERE run_id=? ORDER BY scheduled_for,id',[$runId]):[];}
function sf_pch_latest_certificate():?array{return sf_pch_ready()?sf_admin_fetch_one("SELECT * FROM production_verification_certificates WHERE certificate_status='verified' ORDER BY issued_at DESC,id DESC LIMIT 1"):null;}
function sf_pch_latest_completed():?array{return sf_pch_ready()?sf_admin_fetch_one("SELECT * FROM production_cutover_runs WHERE run_status='completed' AND overall_score=100 ORDER BY completed_at DESC,id DESC LIMIT 1"):null;}

